<?php
require __DIR__.'/../inc/bootstrap.php';admin_required();ensure_pages_table();
$id=(int)($_GET['id']??0);$page=['title'=>'','slug'=>'','content'=>'','is_published'=>1];
if($id){$s=db()->prepare('SELECT * FROM pages WHERE id=?');$s->execute([$id]);$page=$s->fetch()?:$page;}
$error='';if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();$title=trim($_POST['title']??'');$slug=strtolower(trim($_POST['slug']??''));$slug=preg_replace('/[^a-z0-9-]+/','-',$slug);$slug=trim($slug,'-');$content=trim($_POST['content']??'');$published=isset($_POST['is_published'])?1:0;if(!$title||!$slug)$error='Başlık ve sayfa adresi zorunludur.';else{try{if($id){$s=db()->prepare('UPDATE pages SET title=?,slug=?,content=?,is_published=? WHERE id=?');$s->execute([$title,$slug,$content,$published,$id]);}else{$s=db()->prepare('INSERT INTO pages(title,slug,content,is_published) VALUES(?,?,?,?)');$s->execute([$title,$slug,$content,$published]);}header('Location: pages.php');exit;}catch(PDOException $e){$error='Bu sayfa adresi zaten kullanılıyor.';}}}
$pageTitle=$id?'Sayfayı Düzenle':'Sayfa Ekle';$activeMenu='pages';require __DIR__.'/_header.php';
?><div class="page-head"><div><h1><?=e($pageTitle)?></h1><p>Yeni bir içerik sayfası oluştur veya düzenle</p></div></div><section class="card form-card"><?php if($error):?><p class="error"><?=e($error)?></p><?php endif?><form method="post"><input type="hidden" name="csrf" value="<?=csrf()?>"><label>Sayfa başlığı<input name="title" value="<?=e($page['title'])?>" required></label><label>Sayfa adresi<input name="slug" value="<?=e($page['slug'])?>" placeholder="ornek-sayfa" required></label><label>İçerik<textarea class="editor" name="content" placeholder="Sayfa içeriğini yazın..."><?=e($page['content'])?></textarea></label><label><input type="checkbox" name="is_published" value="1" <?=$page['is_published']?'checked':''?>> Yayında</label><button>Sayfayı Kaydet</button></form></section><?php require __DIR__.'/_footer.php';?>
